// Pure-JS bcrypt is not available in this sandbox.
// We provide a SHA-256 based PBKDF2-style hash as a demonstration.
const password = (options.password ?? '').trim();
const rounds   = Math.max(4, Math.min(14, Number(options.rounds ?? 10)));
if (!password) return { output: '', error: 'Please enter a password to hash.' };

// Deterministic salt from crypto.getRandomValues if available, else Math.random
const saltBytes = new Uint8Array(16);
if (typeof crypto !== 'undefined' && crypto.getRandomValues) {
  crypto.getRandomValues(saltBytes);
} else {
  for (let i = 0; i < 16; i++) saltBytes[i] = Math.floor(Math.random() * 256);
}
const saltHex = [...saltBytes].map(b => b.toString(16).padStart(2,'0')).join('');

// TextEncoder to bytes
const enc = new TextEncoder();
const pwBytes = enc.encode(password);

async function pbkdf2Hash(password, salt, iterations) {
  const keyMaterial = await crypto.subtle.importKey(
    'raw', password, { name: 'PBKDF2' }, false, ['deriveBits']
  );
  const bits = await crypto.subtle.deriveBits(
    { name: 'PBKDF2', salt, iterations, hash: 'SHA-256' },
    keyMaterial, 256
  );
  return [...new Uint8Array(bits)].map(b => b.toString(16).padStart(2,'0')).join('');
}

const iterations = Math.pow(2, rounds);
const saltBuf = enc.encode(saltHex);
const hashHex = await pbkdf2Hash(pwBytes, saltBuf, iterations);

const result = [
  `Algorithm:    PBKDF2-SHA256 (bcrypt not available in sandbox)`,
  `Cost rounds:  ${rounds}  (iterations: ${iterations.toLocaleString()})`,
  `Salt (hex):   ${saltHex}`,
  `Hash (hex):   ${hashHex}`,
  '',
  `Stored form:  $pbkdf2-sha256$r=${rounds}$${saltHex}$${hashHex}`,
].join('\n');
return { output: result, outputLanguage: 'text' };

