const t = input.trim().toLowerCase();
// Check if it's a raw seconds input
const rawSeconds = t.match(/^([\d.]+)\s*(s|sec|seconds?)$/);
let totalSeconds;
if (rawSeconds) {
  totalSeconds = parseFloat(rawSeconds[1]);
} else {
  totalSeconds = 0;
  const patterns = [
    { re: /([\d.]+)\s*w(eeks?)?/, mult: 7 * 86400 },
    { re: /([\d.]+)\s*d(ays?)?/, mult: 86400 },
    { re: /([\d.]+)\s*(h(ours?|rs?)?)/, mult: 3600 },
    { re: /([\d.]+)\s*(m(inutes?|ins?)?)(?!s)/, mult: 60 },
    { re: /([\d.]+)\s*(s(econds?|ecs?)?)/, mult: 1 },
  ];
  for (const { re, mult } of patterns) {
    const m = t.match(re);
    if (m) totalSeconds += parseFloat(m[1]) * mult;
  }
}

if (totalSeconds === 0) return { output: '', error: 'Could not parse duration. Try "2 hours 30 minutes" or "9000 seconds".' };

const weeks  = Math.floor(totalSeconds / 604800);
const days   = Math.floor((totalSeconds % 604800) / 86400);
const hours  = Math.floor((totalSeconds % 86400) / 3600);
const mins   = Math.floor((totalSeconds % 3600) / 60);
const secs   = Math.round(totalSeconds % 60);
const parts  = [];
if (weeks)  parts.push(weeks  + ' week'   + (weeks  > 1 ? 's' : ''));
if (days)   parts.push(days   + ' day'    + (days   > 1 ? 's' : ''));
if (hours)  parts.push(hours  + ' hour'   + (hours  > 1 ? 's' : ''));
if (mins)   parts.push(mins   + ' minute' + (mins   > 1 ? 's' : ''));
if (secs)   parts.push(secs   + ' second' + (secs   > 1 ? 's' : ''));

const hms = [hours + days*24 + weeks*168, mins, secs].map(n => String(n).padStart(2,'0')).join(':');
const lines = [
  `Total seconds:  ${totalSeconds}`,
  `HH:MM:SS:       ${hms}`,
  `Human:          ${parts.join(', ')}`,
  `Minutes:        ${(totalSeconds / 60).toFixed(2)}`,
  `Hours:          ${(totalSeconds / 3600).toFixed(4)}`,
];
return { output: lines.join('\n'), outputLanguage: 'text' };

