function classifyIPv4(parts) {
  const [a, b] = parts.map(Number);
  if (a === 127) return 'Loopback';
  if (a === 10) return 'Private (Class A)';
  if (a === 172 && b >= 16 && b <= 31) return 'Private (Class B)';
  if (a === 192 && b === 168) return 'Private (Class C)';
  if (a === 169 && b === 254) return 'Link-Local';
  if (a === 0) return 'Unspecified';
  if (a === 255) return 'Broadcast';
  if (a >= 224 && a <= 239) return 'Multicast';
  return 'Public';
}

const results = [];

// Find IPv4
const ipv4Re = /\b((\d{1,3}\.){3}\d{1,3})\b/g;
let m;
while ((m = ipv4Re.exec(input)) !== null) {
  const ip = m[1];
  const parts = ip.split('.');
  if (parts.every(p => parseInt(p) <= 255)) {
    const nums = parts.map(p => parseInt(p));
    const binary = nums.map(n => n.toString(2).padStart(8, '0')).join('.');
    const hex = nums.map(n => n.toString(16).padStart(2, '0')).join(':');
    const decimal = ((nums[0] << 24) | (nums[1] << 16) | (nums[2] << 8) | nums[3]) >>> 0;
    results.push([
      `IPv4: ${ip}`,
      `  Type:    ${classifyIPv4(parts)}`,
      `  Binary:  ${binary}`,
      `  Hex:     0x${hex.replace(/:/g, '')}`,
      `  Decimal: ${decimal}`,
    ].join('\n'));
  }
}

if (results.length === 0) {
  return { output: 'No valid IP addresses found.', outputLanguage: 'text' };
}
return { output: results.join('\n\n'), outputLanguage: 'text' };

