// ─────────────────────────────────────────────────────────────────────
// Markdown → .docx  (pure JS, zero external deps)
// ZIP method=0 (stored). All XML validated against Word OOXML schema.
// ─────────────────────────────────────────────────────────────────────

// ── CRC-32 ───────────────────────────────────────────────────────────
const CRC_TABLE = (() => {
  const t = new Uint32Array(256);
  for (let i = 0; i < 256; i++) {
    let c = i;
    for (let k = 0; k < 8; k++) c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
    t[i] = c;
  }
  return t;
})();
function crc32(buf) {
  let c = 0xFFFFFFFF;
  for (let i = 0; i < buf.length; i++) c = CRC_TABLE[(c ^ buf[i]) & 0xFF] ^ (c >>> 8);
  return (c ^ 0xFFFFFFFF) >>> 0;
}
function concat(arrays) {
  const total = arrays.reduce((n, a) => n + a.length, 0);
  const out = new Uint8Array(total);
  let off = 0;
  for (const a of arrays) { out.set(a, off); off += a.length; }
  return out;
}

// ── ZIP BUILDER (stored, method=0) ───────────────────────────────────
function u32le(n) { return [(n) & 0xFF, (n >> 8) & 0xFF, (n >> 16) & 0xFF, (n >> 24) & 0xFF]; }
function u16le(n) { return [(n) & 0xFF, (n >> 8) & 0xFF]; }
const enc = s => new TextEncoder().encode(s);

function buildZip(entries) {
  const localParts = [], cdParts = [];
  let offset = 0;
  const DOS_DATE = 0x5380, DOS_TIME = 0x0000;
  for (const { name, data } of entries) {
    const nb = enc(name);
    const crc = crc32(data);
    const lh = new Uint8Array([
      0x50, 0x4B, 0x03, 0x04,
      ...u16le(20), ...u16le(0), ...u16le(0),
      ...u16le(DOS_TIME), ...u16le(DOS_DATE),
      ...u32le(crc), ...u32le(data.length), ...u32le(data.length),
      ...u16le(nb.length), ...u16le(0),
    ]);
    const localEntry = concat([lh, nb, data]);
    localParts.push(localEntry);
    const cd = new Uint8Array([
      0x50, 0x4B, 0x01, 0x02,
      ...u16le(20), ...u16le(20), ...u16le(0), ...u16le(0),
      ...u16le(DOS_TIME), ...u16le(DOS_DATE),
      ...u32le(crc), ...u32le(data.length), ...u32le(data.length),
      ...u16le(nb.length), ...u16le(0), ...u16le(0), ...u16le(0), ...u16le(0),
      ...u32le(0), ...u32le(offset),
    ]);
    cdParts.push(concat([cd, nb]));
    offset += localEntry.length;
  }
  const cdBytes = concat(cdParts);
  const eocd = new Uint8Array([
    0x50, 0x4B, 0x05, 0x06,
    ...u16le(0), ...u16le(0),
    ...u16le(entries.length), ...u16le(entries.length),
    ...u32le(cdBytes.length), ...u32le(offset),
    ...u16le(0),
  ]);
  return concat([...localParts, cdBytes, eocd]);
}

// ── XML ESCAPE ───────────────────────────────────────────────────────
function xe(s) {
  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

// ── INLINE PARSER ────────────────────────────────────────────────────
function parseInline(text) {
  const runs = [];
  const re = /\[([^\]]+)\]\(([^)]+)\)|(\*\*\*(.+?)\*\*\*)|(\*\*(.+?)\*\*)|(\*(.+?)\*)|(`([^`]+)`)/gs;
  let last = 0, m;
  while ((m = re.exec(text)) !== null) {
    if (m.index > last) runs.push({ type: 'run', text: text.slice(last, m.index), bold: false, italic: false, code: false });
    if      (m[1]  !== undefined) runs.push({ type: 'link',  text: m[1],  url: m[2] });
    else if (m[3]  !== undefined) runs.push({ type: 'run',   text: m[4],  bold: true,  italic: true,  code: false });
    else if (m[5]  !== undefined) runs.push({ type: 'run',   text: m[6],  bold: true,  italic: false, code: false });
    else if (m[7]  !== undefined) runs.push({ type: 'run',   text: m[8],  bold: false, italic: true,  code: false });
    else if (m[9]  !== undefined) runs.push({ type: 'run',   text: m[10], bold: false, italic: false, code: true  });
    last = re.lastIndex;
  }
  if (last < text.length) runs.push({ type: 'run', text: text.slice(last), bold: false, italic: false, code: false });
  return runs;
}
function runsToXml(runs, rIdMap) {
  return runs.map(r => {
    if (r.type === 'link') {
      const rid = rIdMap && rIdMap[r.url];
      const run = `<w:r><w:rPr><w:rStyle w:val="Hyperlink"/></w:rPr><w:t xml:space="preserve">${xe(r.text)}</w:t></w:r>`;
      return rid ? `<w:hyperlink r:id="${rid}" w:history="1">${run}</w:hyperlink>` : run;
    }
    const rpr = [];
    if (r.bold)   rpr.push('<w:b/><w:bCs/>');
    if (r.italic) rpr.push('<w:i/><w:iCs/>');
    if (r.code)   rpr.push('<w:rFonts w:ascii="Courier New" w:hAnsi="Courier New"/><w:sz w:val="18"/><w:szCs w:val="18"/><w:shd w:val="clear" w:color="auto" w:fill="F2F2F2"/>');
    const rprXml = rpr.length ? `<w:rPr>${rpr.join('')}</w:rPr>` : '';
    return `<w:r>${rprXml}<w:t xml:space="preserve">${xe(r.text)}</w:t></w:r>`;
  }).join('');
}

// ── BLOCK PARSER ─────────────────────────────────────────────────────
function parseBlocks(md) {
  const lines = md.split(/\r?\n/);
  const blocks = [];
  let i = 0;
  while (i < lines.length) {
    const line = lines[i];
    if (/^\s*$/.test(line)) { i++; continue; }
    // ATX Heading
    const hm = line.match(/^(#{1,6})\s+(.*?)(?:\s+#+)?$/);
    if (hm) { blocks.push({ type: 'heading', level: hm[1].length, text: hm[2].trim() }); i++; continue; }
    // HR
    if (/^([-*_]){3,}$/.test(line.replace(/\s/g, ''))) { blocks.push({ type: 'hr' }); i++; continue; }
    // Table
    if (/^\|/.test(line)) {
      const tl = [];
      while (i < lines.length && /^\|/.test(lines[i])) tl.push(lines[i++]);
      const rows = tl
        .filter(l => !/^\|[\s|:-]+\|?\s*$/.test(l))
        .map(r => r.replace(/^\|/, '').replace(/\|$/, '').split('|').map(c => c.trim()));
      if (rows.length) blocks.push({ type: 'table', rows, hasHeader: tl.length >= 2 });
      continue;
    }
    // Blockquote
    if (/^>\s?/.test(line)) {
      const bl = [];
      while (i < lines.length && /^>\s?/.test(lines[i])) bl.push(lines[i++].replace(/^>\s?/, ''));
      blocks.push({ type: 'blockquote', text: bl.join(' ') });
      continue;
    }
    // Ordered list
    if (/^\d+\.\s/.test(line)) {
      const items = [];
      let expectedNum = 1;
      while (i < lines.length) {
        const om = lines[i].match(/^(\d+)\.\s+(.*)/);
        if (!om) break;
        const num = parseInt(om[1], 10);
        if (items.length > 0 && num <= expectedNum - 1) break;
        expectedNum = num + 1;
        items.push(om[2]);
        i++;
      }
      blocks.push({ type: 'ol', items, startNum: parseInt(line.match(/^(\d+)/)[1], 10) });
      continue;
    }
    // Unordered list
    if (/^[-*+]\s/.test(line)) {
      const items = [];
      while (i < lines.length && /^[-*+]\s/.test(lines[i])) items.push(lines[i++].replace(/^[-*+]\s+/, ''));
      blocks.push({ type: 'ul', items });
      continue;
    }
    // Fenced code block
    if (/^```/.test(line)) {
      const cl = [];
      i++;
      while (i < lines.length && !/^```/.test(lines[i])) cl.push(lines[i++]);
      i++;
      blocks.push({ type: 'code', text: cl.join('\n') });
      continue;
    }
    // Paragraph
    const pl = [];
    while (i < lines.length &&
      !/^\s*$/.test(lines[i]) &&
      !/^#{1,6}\s/.test(lines[i]) &&
      !/^\|/.test(lines[i]) &&
      !/^>\s?/.test(lines[i]) &&
      !/^[-*+]\s/.test(lines[i]) &&
      !/^\d+\.\s/.test(lines[i]) &&
      !/^```/.test(lines[i]) &&
      !/^([-*_]){3,}$/.test(lines[i].replace(/\s/g, ''))
    ) { pl.push(lines[i++]); }
    if (pl.length) blocks.push({ type: 'para', text: pl.join(' ') });
  }
  return blocks;
}

// ── DOCX BODY BUILDER ────────────────────────────────────────────────
function buildDocXml(blocks) {
  const urlToRId = {};
  let ridN = 3; // rId1=styles, rId2=numbering, hyperlinks start at rId3
  let olNumId = 2; // each ol block gets its own numId for counter reset
  const olStartNums = [];
  function getRId(url) { if (!urlToRId[url]) urlToRId[url] = 'rId' + (ridN++); return urlToRId[url]; }
  function collectLinks(text) {
    const re = /\[([^\]]+)\]\(([^)]+)\)/g;
    let m;
    while ((m = re.exec(text)) !== null) getRId(m[2]);
  }
  for (const b of blocks) {
    if (b.text)  collectLinks(b.text);
    if (b.items) b.items.forEach(collectLinks);
    if (b.rows)  b.rows.forEach(row => row.forEach(collectLinks));
  }

  const H = { 1: 'Heading1', 2: 'Heading2', 3: 'Heading3', 4: 'Heading4', 5: 'Heading5', 6: 'Heading6' };
  const body = [];

  for (const b of blocks) {
    switch (b.type) {
      case 'heading':
        body.push(`<w:p><w:pPr><w:pStyle w:val="${H[b.level] || 'Heading1'}"/></w:pPr>${runsToXml(parseInline(b.text), urlToRId)}</w:p>`);
        break;
      case 'para':
        body.push(`<w:p><w:pPr><w:pStyle w:val="Normal"/></w:pPr>${runsToXml(parseInline(b.text), urlToRId)}</w:p>`);
        break;
      case 'blockquote':
        body.push(`<w:p><w:pPr><w:pStyle w:val="Quote"/></w:pPr>${runsToXml(parseInline(b.text), urlToRId)}</w:p>`);
        break;
      case 'hr':
        body.push('<w:p><w:pPr><w:pBdr><w:bottom w:val="single" w:sz="6" w:space="1" w:color="AAAAAA"/></w:pBdr></w:pPr></w:p>');
        break;
      case 'ul':
        for (const item of b.items)
          body.push(`<w:p><w:pPr><w:pStyle w:val="ListBullet"/></w:pPr>${runsToXml(parseInline(item), urlToRId)}</w:p>`);
        break;
      case 'ol': {
        olStartNums.push(b.startNum || 1);
        const nid = olNumId++;
        for (const item of b.items)
          body.push(`<w:p><w:pPr><w:pStyle w:val="ListNumber"/><w:numPr><w:ilvl w:val="0"/><w:numId w:val="${nid}"/></w:numPr></w:pPr>${runsToXml(parseInline(item), urlToRId)}</w:p>`);
        break;
      }
      case 'code':
        for (const line of b.text.split('\n'))
          body.push(`<w:p><w:pPr><w:pStyle w:val="Normal"/></w:pPr><w:r><w:rPr><w:rFonts w:ascii="Courier New" w:hAnsi="Courier New"/><w:sz w:val="18"/><w:szCs w:val="18"/><w:shd w:val="clear" w:color="auto" w:fill="F2F2F2"/></w:rPr><w:t xml:space="preserve">${xe(line)}</w:t></w:r></w:p>`);
        break;
      case 'table': {
        const rows = b.rows;
        if (!rows || !rows.length) break;
        const nc = Math.max(...rows.map(r => r.length));
        const cw = Math.floor(9000 / nc);
        const tblPr = `<w:tblPr><w:tblStyle w:val="TableGrid"/><w:tblW w:w="0" w:type="auto"/><w:tblLook w:val="04A0" w:firstRow="1" w:lastRow="0" w:firstColumn="1" w:lastColumn="0" w:noHBand="0" w:noVBand="1"/></w:tblPr>`;
        const tblGrid = `<w:tblGrid>${Array(nc).fill(`<w:gridCol w:w="${cw}"/>`).join('')}</w:tblGrid>`;
        const rowsXml = rows.map((row, ri) => {
          const isHdr = ri === 0 && b.hasHeader;
          const cells = Array.from({ length: nc }, (_, ci) => {
            const cell = row[ci] || '';
            const fill = isHdr ? '<w:shd w:val="clear" w:color="auto" w:fill="D9E2F3"/>' : '';
            const tcPr = `<w:tcPr><w:tcW w:w="${cw}" w:type="dxa"/>${fill}</w:tcPr>`;
            const runs = parseInline(cell).map(r => {
              if (r.type === 'link') {
                const rid = urlToRId[r.url];
                const run = `<w:r><w:rPr><w:rStyle w:val="Hyperlink"/>${isHdr ? '<w:b/><w:bCs/>' : ''}</w:rPr><w:t xml:space="preserve">${xe(r.text)}</w:t></w:r>`;
                return rid ? `<w:hyperlink r:id="${rid}" w:history="1">${run}</w:hyperlink>` : run;
              }
              const rpr = [];
              if (r.bold || isHdr) rpr.push('<w:b/><w:bCs/>');
              if (r.italic) rpr.push('<w:i/><w:iCs/>');
              if (r.code)   rpr.push('<w:rFonts w:ascii="Courier New" w:hAnsi="Courier New"/><w:sz w:val="18"/>');
              const rprXml = rpr.length ? `<w:rPr>${rpr.join('')}</w:rPr>` : '';
              return `<w:r>${rprXml}<w:t xml:space="preserve">${xe(r.text)}</w:t></w:r>`;
            }).join('');
            return `<w:tc>${tcPr}<w:p>${runs}</w:p></w:tc>`;
          });
          return `<w:tr>${cells.join('')}</w:tr>`;
        }).join('');
        body.push(`<w:tbl>${tblPr}${tblGrid}${rowsXml}</w:tbl>`);
        break;
      }
    }
  }

  const relsXml = Object.entries(urlToRId).map(([url, rid]) =>
    `<Relationship Id="${rid}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/hyperlink" Target="${xe(url)}" TargetMode="External"/>`
  ).join('');

  return { bodyXml: body.join(''), relsXml, olStartNums };
}

