// Numbering: w:nsid, w:multiLevelType, w:tmpl are required by Word.
// Bullet uses Symbol font char \uF0B7 (the solid bullet in Symbol encoding).
// Each ol block gets its own numId (2, 3, 4, …) so Word resets the counter.
function buildNumberingXml(olStartNums) {
  const nums = [`<w:num w:numId="1"><w:abstractNumId w:val="0"/></w:num>`];
  for (let i = 0; i < olStartNums.length; i++) {
    nums.push(
      `<w:num w:numId="${i + 2}">` +
        `<w:abstractNumId w:val="1"/>` +
        `<w:lvlOverride w:ilvl="0"><w:startOverride w:val="${olStartNums[i]}"/></w:lvlOverride>` +
      `</w:num>`
    );
  }
  return `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n` +
    `<w:numbering ${NSMAP}>\n` +
    `  <w:abstractNum w:abstractNumId="0">\n` +
    `    <w:nsid w:val="00000001"/>\n` +
    `    <w:multiLevelType w:val="singleLevel"/>\n` +
    `    <w:tmpl w:val="00000001"/>\n` +
    `    <w:lvl w:ilvl="0">\n` +
    `      <w:start w:val="1"/>\n` +
    `      <w:numFmt w:val="bullet"/>\n` +
    `      <w:lvlText w:val="\uF0B7"/>\n` +
    `      <w:lvlJc w:val="left"/>\n` +
    `      <w:pPr><w:tabs><w:tab w:val="num" w:pos="360"/></w:tabs><w:ind w:left="360" w:hanging="360"/></w:pPr>\n` +
    `      <w:rPr><w:rFonts w:ascii="Symbol" w:hAnsi="Symbol" w:hint="default"/></w:rPr>\n` +
    `    </w:lvl>\n` +
    `  </w:abstractNum>\n` +
    `  <w:abstractNum w:abstractNumId="1">\n` +
    `    <w:nsid w:val="00000002"/>\n` +
    `    <w:multiLevelType w:val="singleLevel"/>\n` +
    `    <w:tmpl w:val="00000002"/>\n` +
    `    <w:lvl w:ilvl="0">\n` +
    `      <w:start w:val="1"/>\n` +
    `      <w:numFmt w:val="decimal"/>\n` +
    `      <w:lvlText w:val="%1."/>\n` +
    `      <w:lvlJc w:val="left"/>\n` +
    `      <w:pPr><w:tabs><w:tab w:val="num" w:pos="360"/></w:tabs><w:ind w:left="360" w:hanging="360"/></w:pPr>\n` +
    `    </w:lvl>\n` +
    `  </w:abstractNum>\n` +
    nums.join('\n') + '\n' +
    `</w:numbering>`;
}

