  <Override PartName="/word/settings.xml"  ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.settings+xml"/>
</Types>`;

  const rootRelsXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/>
</Relationships>`;

  const zipBytes = buildZip([
    { name: '[Content_Types].xml',         data: enc(ctXml) },
    { name: '_rels/.rels',                  data: enc(rootRelsXml) },
    { name: 'word/document.xml',            data: enc(docXml) },
    { name: 'word/_rels/document.xml.rels', data: enc(docRelsXml) },
    { name: 'word/styles.xml',              data: enc(STYLES_XML) },
    { name: 'word/numbering.xml',           data: enc(buildNumberingXml(olStartNums)) },
    { name: 'word/settings.xml',            data: enc(SETTINGS_XML) },
  ]);

  let b64 = '';
  const CHUNK = 8192;
  for (let i = 0; i < zipBytes.length; i += CHUNK)
    b64 += String.fromCharCode(...zipBytes.subarray(i, i + CHUNK));

  return { output: btoa(b64), outputEncoding: 'base64', outputLanguage: 'binary' };
} catch (err) {
  return { output: '', error: err instanceof Error ? err.message : String(err) };
}

const ZONES = [
  { label: 'UTC',              tz: 'UTC' },
  { label: 'New York (ET)',    tz: 'America/New_York' },
  { label: 'Chicago (CT)',     tz: 'America/Chicago' },
  { label: 'Denver (MT)',      tz: 'America/Denver' },
  { label: 'Los Angeles (PT)',tz: 'America/Los_Angeles' },
  { label: 'London (GMT/BST)',tz: 'Europe/London' },
  { label: 'Paris (CET/CEST)',tz: 'Europe/Paris' },
  { label: 'Moscow (MSK)',    tz: 'Europe/Moscow' },
  { label: 'Dubai (GST)',     tz: 'Asia/Dubai' },
  { label: 'India (IST)',     tz: 'Asia/Kolkata' },
  { label: 'Singapore (SGT)',tz: 'Asia/Singapore' },
  { label: 'Tokyo (JST)',     tz: 'Asia/Tokyo' },
  { label: 'Sydney (AET)',    tz: 'Australia/Sydney' },
];

const t = input.trim();
let dt = new Date(t);
if (isNaN(dt.getTime())) {
  // Try to handle common formats
  dt = new Date(t.replace(/\//g, '-'));
}
if (isNaN(dt.getTime())) {
  return { output: '', error: 'Could not parse the datetime. Try ISO 8601 format: 2024-07-15T14:30:00Z' };
}

const maxLen = Math.max(...ZONES.map(z => z.label.length));
const lines = [`Input:  ${dt.toISOString()}`, ''];
for (const { label, tz } of ZONES) {
  try {
    const str = dt.toLocaleString('en-US', {
      timeZone: tz,
      weekday: 'short',
      year: 'numeric', month: 'short', day: '2-digit',
      hour: '2-digit', minute: '2-digit', second: '2-digit',
      hour12: false,
    });
    lines.push(label.padEnd(maxLen) + '  ' + str);
  } catch {
    lines.push(label.padEnd(maxLen) + '  (unavailable)');
  }
}
return { output: lines.join('\n'), outputLanguage: 'text' };

const raw = input.trim().replace(/[,_]/g, '');
const n = parseFloat(raw);
if (isNaN(n)) return { output: '', error: 'Input is not a valid number.' };

function ordinal(n) {
  const abs = Math.abs(Math.round(n));
  const s = ['th','st','nd','rd'];
  const v = abs % 100;
  return abs + (s[(v-20)%10]||s[v]||s[0]);
}

const isInt = Number.isInteger(n);
const lines = [
  `Input:              ${raw}`,
  `Locale string:      ${n.toLocaleString()}`,
  `Scientific:         ${n.toExponential()}`,
];
if (isInt) {
  lines.push(`Hexadecimal:        0x${Math.abs(n).toString(16).toUpperCase()}${n < 0 ? ' (negative)' : ''}`);
  lines.push(`Binary:             ${n < 0 ? '-' : ''}0b${Math.abs(n).toString(2)}`);
  lines.push(`Octal:              ${n < 0 ? '-' : ''}0o${Math.abs(n).toString(8)}`);
  lines.push(`Ordinal:            ${ordinal(n)}`);
}
lines.push(`Absolute value:     ${Math.abs(n)}`);
if (isInt) lines.push(`Bits needed:        ${Math.floor(Math.log2(Math.abs(n) || 1)) + 1}`);
return { output: lines.join('\n'), outputLanguage: 'text' };

plugins.generateCode:
const type  = options.type  ?? 'arithmetic';
const start = Number(options.start ?? 1);
const step  = Number(options.step  ?? 1);
const count = Math.max(1, Math.min(100, Number(options.count ?? 10)));
const minR  = Number(options.min ?? 1);
const maxR  = Number(options.max ?? 100);
const seq = [];
if (type === 'arithmetic') {
  for (let i = 0; i < count; i++) seq.push(start + i * step);
} else if (type === 'geometric') {
  const ratio = step === 0 ? 1 : step;
  for (let i = 0; i < count; i++) seq.push(start * Math.pow(ratio, i));
} else if (type === 'fibonacci') {
  let a = start, b = step === 0 ? 1 : step;
  seq.push(a);
  if (count > 1) seq.push(b);
  for (let i = 2; i < count; i++) { const c = a + b; seq.push(c); a = b; b = c; }
} else {
  for (let i = 0; i < count; i++) seq.push(Math.floor(Math.random() * (maxR - minR + 1)) + minR);
}
return { output: seq.join(', '), outputLanguage: 'text' };

plugins.executeCode:
const BE_FORMS = /\b(am|is|are|was|were|be|been|being)\b/i;
const PAST_PARTICIPLE = /\b(\w+ed|\w+en|built|bought|brought|caught|come|dealt|done|drawn|drunk|driven|eaten|fallen|felt|found|given|gone|got|grown|heard|held|kept|known|led|left|lent|lost|made|meant|met|paid|put|read|run|said|seen|sent|shown|shut|slept|spent|spoken|stood|taken|taught|told|thought|understood|won|written|broken|chosen|frozen|stolen|begun|rung|sung|swum|thrown)\b/i;

// Split into sentences
const sentences = input.match(/[^.!?]+[.!?]+/g) || [input];
const passive = [];
const active  = [];

for (const s of sentences) {
  const trimmed = s.trim();
  if (!trimmed) continue;
  // Heuristic: contains a be-form followed within 3 words by a past participle
  const words = trimmed.split(/\s+/);
  let found = false;
  for (let i = 0; i < words.length - 1; i++) {
    if (BE_FORMS.test(words[i])) {
      for (let j = i + 1; j <= Math.min(i + 3, words.length - 1); j++) {
        if (PAST_PARTICIPLE.test(words[j])) {
          found = true;
          break;
        }
      }
    }
    if (found) break;
  }
  if (found) passive.push(trimmed);
  else active.push(trimmed);
}

const total = passive.length + active.length;
const pct = total > 0 ? Math.round(passive.length / total * 100) : 0;
const lines = [
  `Passive voice: ${passive.length} / ${total} sentences (${pct}%)`,
  `Result: ${pct <= 10 ? 'PASS' : pct <= 25 ? 'ACCEPTABLE' : 'FAIL'} (target ≤ 10%)`,
  '',
];
if (passive.length > 0) {
  lines.push('Flagged sentences:');
  passive.forEach((s, i) => lines.push(`  ${i + 1}. ${s}`));
}
return { output: lines.join('\n'), outputLanguage: 'text' };

const lines = input.split('\n');
const out = [];
let indent = 0;
for (const raw of lines) {
  const line = raw.trim();
  if (!line) { if (out.length && out[out.length-1] !== '') out.push(''); continue; }
  // Decrease indent before closing brace
  if (line.startsWith('}')) indent = Math.max(0, indent - 1);
  // Normalize spaces around '='
  let formatted = line.replace(/\s*=\s*/g, ' = ');
