    `  Major:      ${v.major}  (breaking changes)`,
    `  Minor:      ${v.minor}  (new features, backward-compatible)`,
    `  Patch:      ${v.patch}  (bug fixes)`,
  ];
  if (v.pre)   lines.push(`  Pre-release: ${v.pre}`);
  if (v.build) lines.push(`  Build meta:  ${v.build}`);
  lines.push(`  Stable: ${v.pre ? 'No (pre-release)' : 'Yes'}`);
  return lines.join('\n');
}

